import{_ as e,c as t}from"./app.e53bf642.js";const i={},r=t('<h1 id="user-story" tabindex="-1"><a class="header-anchor" href="#user-story" aria-hidden="true">#</a> User Story</h1><p>User stories are development tasks often expressed as &quot;persona + need + purpose&quot;.</p><ul><li>use non-technical language to provide context for the development team and their efforts.</li><li>the team knows why they are building, what they&#39;er building, and what value it creates.</li><li>stories keep the foucs on the user.</li><li>stories enable collaboration.</li><li>stories drive creative solutions.</li><li>stories create momentum.</li></ul><h2 id="how-to-write-user-stories" tabindex="-1"><a class="header-anchor" href="#how-to-write-user-stories" aria-hidden="true">#</a> How to write user stories</h2><ul><li>Defination of &quot;Done&quot;</li><li>Outline subtasks or tasks</li><li>User personas</li><li>Ordered Steps</li><li>Listen to feedback</li><li>Time</li></ul><h2 id="user-story-template-and-examples" tabindex="-1"><a class="header-anchor" href="#user-story-template-and-examples" aria-hidden="true">#</a> User story template and examples</h2><p>As a [persona], I [want to], [so that].</p><ul><li>&quot;As a [persona]&quot;: we understand how that person works,how they think and what they feel.</li><li>&quot;Wants to&quot;: Here we\u2019re describing their intent \u2014 not the features they use. What is it they\u2019re actually trying to achieve? This statement should be implementation free \u2014 if you\u2019re describing any part of the UI and not what the user goal is you&#39;re missing the point.</li><li>&quot;So that&quot;: how does their immediate desire to do something this fit into their bigger picture? What\u2019s the overall benefit they\u2019re trying to achieve? What is the big problem that needs solving?</li></ul>',8);function s(o,a){return r}var l=e(i,[["render",s],["__file","user-story-2.html.vue"]]);export{l as default};
